import { supabase } from '../../../../infra/db/supabase';
import { TaskStatus, Task, TaskExecution } from '../../../../shared/types/task';
import { orchestrateWorkflow } from '../../../../modules/workflows/execution-orchestrator';

export async function updateTaskStatus(task_id: string, status: TaskStatus): Promise<Task> {
    const { data, error } = await supabase
        .from('tasks')
        .update({ status })
        .eq('id', task_id)
        .select()
        .single();

    if (error) {
        console.error('Error updating task status:', error);
        throw new Error('Failed to update task status');
    }

    // If a task is manually moved to DONE, orchestrate the next steps
    if (status === 'DONE') {
        orchestrateWorkflow(task_id).catch(console.error);
    }

    return data as Task;
}

export async function saveTaskExecutionResult(task_id: string, ai_result: string): Promise<{ execution: TaskExecution, task: Task }> {
    // 1. Insert execution record
    const { data: execution, error: execError } = await supabase
        .from('task_executions')
        .insert([{ task_id, ai_result }])
        .select()
        .single();

    if (execError) throw new Error(`Failed to save execution: ${execError.message}`);

    // 2. Update task output and mark as DONE
    const { data: task, error: taskError } = await supabase
        .from('tasks')
        .update({ ai_output: ai_result, status: 'DONE' })
        .eq('id', task_id)
        .select()
        .single();

    if (taskError) throw new Error(`Failed to update task: ${taskError.message}`);

    // 3. Orchestrate next steps in the graph
    // We don't await this to keep the response snappy, or we can await it if we want strict consistency.
    // Let's NOT await it for better UX, but handle it as a background process.
    orchestrateWorkflow(task_id).catch(console.error);

    return { execution: execution as TaskExecution, task: task as Task };
}

export async function saveHumanFeedback(task_id: string, feedback: string): Promise<Task> {
    const { data: task, error: taskError } = await supabase
        .from('tasks')
        .update({ ai_output: feedback, status: 'DONE' })
        .eq('id', task_id)
        .select()
        .single();

    if (taskError) throw new Error(`Failed to save feedback: ${taskError.message}`);

    // Orchestrate next steps in the graph
    orchestrateWorkflow(task_id).catch(console.error);

    return task as Task;
}
